const ALL_CATEGORIES = ["全部",...new Set(QB.map(q=>q.examCategory))];
const LS="lawquiz_prog_v1";
const CUSTOM_LS="lawquiz_custom_v1";
function load(){
  try{
    // 自動搬移舊版 key (lq114v1) 的進度
    const legacy=localStorage.getItem("lq114v1");
    if(legacy&&!localStorage.getItem(LS)){
      localStorage.setItem(LS,legacy);
      localStorage.removeItem("lq114v1");
    }
    const r=localStorage.getItem(LS);
    return r?JSON.parse(r):{};
  }catch{return{}}
}
function save(d){try{localStorage.setItem(LS,JSON.stringify(d))}catch{}}
function loadCustom(){try{const r=localStorage.getItem(CUSTOM_LS);return r?JSON.parse(r):[]}catch{return[]}}
function saveCustom(d){try{localStorage.setItem(CUSTOM_LS,JSON.stringify(d))}catch{}}

const BOOKMARK_LS="lawquiz_bookmarks_v1";
function loadBookmarks(){try{const r=localStorage.getItem(BOOKMARK_LS);return r?new Set(JSON.parse(r)):new Set()}catch{return new Set()}}
function saveBookmarks(s){try{localStorage.setItem(BOOKMARK_LS,JSON.stringify([...s]))}catch{}}
const SESSION_LS="lawquiz_session_v1";
function loadSession(){try{const r=localStorage.getItem(SESSION_LS);return r?JSON.parse(r):null}catch{return null}}
function saveSession(d){try{localStorage.setItem(SESSION_LS,JSON.stringify(d))}catch{}}
function clearSession(){try{localStorage.removeItem(SESSION_LS)}catch{}}
function fmtTime(s){const m=Math.floor(s/60),sec=s%60;return m>0?`${m}分${sec.toString().padStart(2,"0")}秒`:`${sec} 秒`}

// 驗證匯入題目格式
const REQUIRED=["id","year","examCategory","examGroup","subject","text","options","answer"];
function validateQ(q,idx){
  for(const k of REQUIRED){
    if(q[k]===undefined||q[k]===null)return`第 ${idx+1} 題缺少欄位「${k}」`;
  }
  if(!Array.isArray(q.options)||q.options.length!==4)return`第 ${idx+1} 題 options 須為 4 個選項的陣列`;
  if(typeof q.answer!=="number"||q.answer<0||q.answer>3)return`第 ${idx+1} 題 answer 須為 0–3 的整數`;
  return null;
}
function shuffle(a){const b=[...a];for(let i=b.length-1;i>0;i--){const j=Math.floor(Math.random()*(i+1));[b[i],b[j]]=[b[j],b[i]];}return b;}
function getStars(p,id){return p[id]?.stars??["e","e","e","e","e"]}
function Star({t}){
  const c=t==="g"?"#f59e0b":t==="r"?"#ef4444":"#c8c8d0";
  return <span style={{color:c,fontSize:"0.9rem",filter:t!=="e"?`drop-shadow(0 0 3px ${c}99)`:"none"}}>{t==="e"?"☆":"★"}</span>
}

// ──────────────────────────────
// design tokens
// ──────────────────────────────
const T={
  bg:"#f5f1ea",white:"#fffefb",
  navy:"#16213e",ink:"#2c2c44",muted:"#7a7a8c",
  bdr:"#e2ddd5",
  gold:"#c07c0a",goldBg:"#fef8e8",
  blue:"#2563eb",blueBg:"#eff6ff",
  green:"#166534",greenBg:"#f0fdf4",
  red:"#991b1b",redBg:"#fef2f2",
  accent:"#f59e0b",
};

const LAW_CONFIG={
  "民法":      {pcode:"B0000001",name:"民法"},
  "民事訴訟法":{pcode:"B0010001",name:"民事訴訟法"},
  "刑法":      {pcode:"C0000001",name:"刑法"},
  "刑事訴訟法":{pcode:"C0010001",name:"刑事訴訟法"},
  "法律倫理":  {pcode:"D0120014",name:"律師倫理規範"},
  "憲法":      {pcode:"A0000001",name:"中華民國憲法"},
  "行政法":    {pcode:"A0150001",name:"行政程序法"},
};
const QUICK_LAWS=[
  {pcode:"C0000001",name:"刑法"},
  {pcode:"B0000001",name:"民法"},
  {pcode:"C0010001",name:"刑事訴訟法"},
  {pcode:"B0010001",name:"民事訴訟法"},
  {pcode:"A0000001",name:"中華民國憲法"},
  {pcode:"A0030002",name:"憲法增修條文"},
  {pcode:"A0030086",name:"憲法訴訟法"},
  {pcode:"D0120014",name:"律師倫理規範"},
  {pcode:"A0150001",name:"行政程序法"},
  {pcode:"C0060001",name:"毒品危害防制條例"},
  {pcode:"D0050001",name:"公司法"},
  {pcode:"G0380037",name:"證券交易法"},
  {pcode:"H0020023",name:"保險法"},
  {pcode:"G0380108",name:"票據法"},
  {pcode:"A0060067",name:"地方制度法"},
  {pcode:"A0150052",name:"行政罰法"},
  {pcode:"A0030054",name:"行政訴訟法"},
  {pcode:"A0030055",name:"訴願法"},
  {pcode:"B0010058",name:"家事事件法"},
  {pcode:"B0010059",name:"強制執行法"},
];
function getLawUrl(pcode,articleNo){
  if(articleNo)return`https://law.moj.gov.tw/LawClass/LawSingle.aspx?pcode=${pcode}&flno=${articleNo}`;
  return`https://law.moj.gov.tw/LawClass/LawAll.aspx?pcode=${pcode}`;
}

export default function App(){
  const [cat,setCat]=useState("全部");
  const [yr,setYr]=useState("全部");
  const [grp,setGrp]=useState("全部");
  const [subj,setSubj]=useState("全部");
  // 考試模式篩選（多選，空 Set = 全部）
  const [exCats,setExCats]=useState(new Set());
  const [exYrs,setExYrs]=useState(new Set());
  const [exGrps,setExGrps]=useState(new Set());
  const [exSubjs,setExSubjs]=useState(new Set());
  const [queue,setQueue]=useState([]);
  const [qi,setQi]=useState(0);
  const [sel,setSel]=useState(null);
  const [answered,setAnswered]=useState(false);
  const [prog,setProg]=useState(load);
  const [mode,setMode]=useState("filter");
  // 自訂題目
  const [customQ,setCustomQ]=useState(loadCustom);
  const [showImport,setShowImport]=useState(false);
  const [importText,setImportText]=useState("");
  const [importErr,setImportErr]=useState("");
  const [importOk,setImportOk]=useState("");
  // 書籤
  const [bookmarks,setBookmarks]=useState(()=>loadBookmarks());
  // 每個 queue 位置的已選答案：{ [queueIndex]: selectedOptionIndex }
  const [answers,setAnswers]=useState({});
  // 每題計時
  const [qTimer,setQTimer]=useState(0);
  // 本輪總計時（秒）
  const [totalElapsed,setTotalElapsed]=useState(0);
  const [drawerOpen,setDrawerOpen]=useState(false);
  const [drawerLaw,setDrawerLaw]=useState(null);
  const [drawerLawInput,setDrawerLawInput]=useState("");
  const [drawerNo,setDrawerNo]=useState("");
  const timerRef=useRef(null);
  const totalElapsedRef=useRef(0); // 用 ref 在 interval 內讀取最新值

  // 合併題庫
  const ALL_Q=useMemo(()=>[...QB,...customQ],[customQ]);

  // 動態選項（每層依上層篩選）
  const years  =useMemo(()=>{
    const all=ALL_Q.filter(q=>cat==="全部"||q.examCategory===cat).map(q=>q.year);
    return ["全部",...new Set(all)];
  },[cat,ALL_Q]);
  const groups =useMemo(()=>{
    const all=ALL_Q.filter(q=>
      (cat==="全部"||q.examCategory===cat)&&
      (yr==="全部"||q.year===yr)
    ).map(q=>q.examGroup);
    return ["全部",...new Set(all)];
  },[cat,yr,ALL_Q]);
  const subjects=useMemo(()=>{
    const all=ALL_Q.filter(q=>
      (cat==="全部"||q.examCategory===cat)&&
      (yr==="全部"||q.year===yr)&&
      (grp==="全部"||q.examGroup===grp)
    ).map(q=>q.subject);
    return ["全部",...new Set(all)];
  },[cat,yr,grp,ALL_Q]);
  const filtered=useMemo(()=>ALL_Q.filter(q=>
    (cat==="全部"||q.examCategory===cat)&&
    (yr==="全部"||q.year===yr)&&
    (grp==="全部"||q.examGroup===grp)&&
    (subj==="全部"||q.subject===subj)
  ),[cat,yr,grp,subj,ALL_Q]);

  // 錯題 & 書籤集合
  const mistakeQs=useMemo(()=>ALL_Q.filter(q=>prog[q.id]?.stars.some(s=>s==="r")),[ALL_Q,prog]);
  const bookmarkQs=useMemo(()=>ALL_Q.filter(q=>bookmarks.has(q.id)),[ALL_Q,bookmarks]);

  // 科目進度統計（依目前篩選範圍）
  const subjectStats=useMemo(()=>{
    const s={};
    for(const q of filtered){
      if(!s[q.subject])s[q.subject]={total:0,mastered:0,practiced:0};
      s[q.subject].total++;
      const p=prog[q.id];
      if(p){s[q.subject].practiced++;if(p.stars?.every(v=>v==="g"))s[q.subject].mastered++;}
    }
    return s;
  },[filtered,prog]);

  // 考試模式篩選選項（多選聯動）
  const exYearOpts=useMemo(()=>{
    const all=ALL_Q.filter(q=>exCats.size===0||exCats.has(q.examCategory)).map(q=>q.year);
    return [...new Set(all)];
  },[exCats,ALL_Q]);
  const exGrpOpts=useMemo(()=>{
    const all=ALL_Q.filter(q=>
      (exCats.size===0||exCats.has(q.examCategory))&&
      (exYrs.size===0||exYrs.has(q.year))
    ).map(q=>q.examGroup);
    return [...new Set(all)];
  },[exCats,exYrs,ALL_Q]);
  const exSubjOpts=useMemo(()=>{
    const all=ALL_Q.filter(q=>
      (exCats.size===0||exCats.has(q.examCategory))&&
      (exYrs.size===0||exYrs.has(q.year))&&
      (exGrps.size===0||exGrps.has(q.examGroup))
    ).map(q=>q.subject);
    return [...new Set(all)];
  },[exCats,exYrs,exGrps,ALL_Q]);
  const examFiltered=useMemo(()=>ALL_Q.filter(q=>
    (exCats.size===0||exCats.has(q.examCategory))&&
    (exYrs.size===0||exYrs.has(q.year))&&
    (exGrps.size===0||exGrps.has(q.examGroup))&&
    (exSubjs.size===0||exSubjs.has(q.subject))
  ),[exCats,exYrs,exGrps,exSubjs,ALL_Q]);

  // 多選 toggle 輔助
  function toggleSet(setter,val){setter(prev=>{const n=new Set(prev);if(n.has(val))n.delete(val);else n.add(val);return n;});}
  // 考試類組所有選項（不含「全部」，多選模式不需要「全部」pill）
  const ALL_CAT_OPTS=useMemo(()=>[...new Set(ALL_Q.map(q=>q.examCategory))],[ALL_Q]);

  // 每次換題：重設每題計時，totalElapsed 繼續累積
  useEffect(()=>{
    if(mode!=="quiz"&&mode!=="exam")return;
    setQTimer(0);
    clearInterval(timerRef.current);
    timerRef.current=setInterval(()=>{
      setQTimer(t=>t+1);
      setTotalElapsed(t=>{const n=t+1;totalElapsedRef.current=n;return n;});
    },1000);
    return()=>clearInterval(timerRef.current);
  },[qi,mode]);
  // 作答後停止每題計時（考試模式：選完即停，不顯示解析但計時停）
  useEffect(()=>{if(answered)clearInterval(timerRef.current);},[answered]);

  // sessionExists：用 state 明確追蹤，避免 stale closure 問題
  const [sessionExists,setSessionExists]=useState(()=>{
    const s=loadSession();
    return !!(s&&s.queue&&s.queue.length>0&&(s.qi??0)<s.queue.length);
  });

  const cq=queue[qi]??null;

  // 中途退出首頁：直接在 handler 存 session（可拿到最新 queue/qi/answers）
  function goHome(){
    clearInterval(timerRef.current);
    if(queue.length>0){
      saveSession({queue:queue.map(q=>q.id),qi,answers,elapsed:totalElapsedRef.current});
      setSessionExists(true);
    }
    setMode("filter");
  }

  const start=useCallback(()=>{
    if(!filtered.length)return;
    clearSession();setSessionExists(false);
    totalElapsedRef.current=0;setTotalElapsed(0);
    setQueue(shuffle(filtered));setQi(0);setSel(null);setAnswered(false);setAnswers({});setMode("quiz");
  },[filtered]);

  const startMistake=useCallback(()=>{
    if(!mistakeQs.length)return;
    clearSession();setSessionExists(false);
    totalElapsedRef.current=0;setTotalElapsed(0);
    setQueue(shuffle(mistakeQs));setQi(0);setSel(null);setAnswered(false);setAnswers({});setMode("quiz");
  },[mistakeQs]);

  const startBookmark=useCallback(()=>{
    if(!bookmarkQs.length)return;
    clearSession();setSessionExists(false);
    totalElapsedRef.current=0;setTotalElapsed(0);
    setQueue(shuffle(bookmarkQs));setQi(0);setSel(null);setAnswered(false);setAnswers({});setMode("quiz");
  },[bookmarkQs]);

  // 繼續測驗：從 session 還原狀態（練習或考試模式皆適用）
  const continueSession=useCallback(()=>{
    const s=loadSession();
    if(!s)return;
    const qMap=Object.fromEntries(ALL_Q.map(q=>[q.id,q]));
    const restoredQueue=s.queue.map(id=>qMap[id]).filter(Boolean);
    if(!restoredQueue.length)return;
    const restoredElapsed=s.elapsed??0;
    totalElapsedRef.current=restoredElapsed;
    setTotalElapsed(restoredElapsed);
    setQueue(restoredQueue);
    setQi(s.qi??0);
    setSessionExists(false);
    if(s.sessionMode==="exam"){
      const restored=s.examAnswers??{};
      setExamAnswers(restored);
      setAnswers({});
      const restoredAns=restored[s.qi??0];
      if(restoredAns!==undefined){setSel(restoredAns);setAnswered(true);}
      else{setSel(null);setAnswered(false);}
      setMode("exam");
    } else {
      const restored=s.answers??{};
      setAnswers(restored);
      setExamAnswers({});
      const restoredAns=restored[s.qi??0];
      if(restoredAns!==undefined){setSel(restoredAns);setAnswered(true);}
      else{setSel(null);setAnswered(false);}
      setMode("quiz");
    }
  },[ALL_Q]);

  // 考試模式
  const [examAnswers,setExamAnswers]=useState({});

  const startExam=useCallback(()=>{
    if(!examFiltered.length)return;
    const pool=shuffle(examFiltered);
    const examQ=pool.slice(0,75);
    clearSession();setSessionExists(false);
    totalElapsedRef.current=0;setTotalElapsed(0);
    setQueue(examQ);setQi(0);setSel(null);setAnswered(false);
    setAnswers({});setExamAnswers({});
    setMode("exam");
  },[examFiltered]);

  // 考試模式中途退出：存 session（sessionMode:"exam"）
  function goHomeFromExam(){
    clearInterval(timerRef.current);
    if(queue.length>0){
      saveSession({
        queue:queue.map(q=>q.id),
        qi,
        answers:{},
        examAnswers,
        elapsed:totalElapsedRef.current,
        sessionMode:"exam"
      });
      setSessionExists(true);
    }
    setMode("filter");
  }

  function toggleBookmark(id){
    const nb=new Set(bookmarks);
    if(nb.has(id))nb.delete(id);else nb.add(id);
    setBookmarks(nb);saveBookmarks(nb);
  }

  function handleAns(i){
    if(answered)return;
    setSel(i);setAnswered(true);
    setAnswers(prev=>({...prev,[qi]:i}));
    const id=cq.id,ok=i===cq.answer;
    const prev=prog[id]??{stars:["e","e","e","e","e"],attempts:0};
    let stars=[...prev.stars];
    if(ok){const idx=stars.findIndex(s=>s!=="g");if(idx!==-1)stars[idx]="g";}
    else{if(stars.some(s=>s==="g")){stars=["e","e","e","e","e"];}else{const idx=stars.findIndex(s=>s!=="r");if(idx!==-1)stars[idx]="r";}}
    const np={...prog,[id]:{...prev,stars,attempts:prev.attempts+1}};
    setProg(np);save(np);
    const cfg=LAW_CONFIG[cq.subject];
    if(cfg&&!drawerLaw)setDrawerLaw(cfg);
    setDrawerOpen(true);
  }
  function next(){
    setDrawerOpen(false);setDrawerNo("");
    if(qi+1>=queue.length){
      clearSession();setSessionExists(false);
      setMode("done");
    } else{
      const nextQi=qi+1;
      const nextAns=answers[nextQi];
      setQi(nextQi);
      if(nextAns!==undefined){setSel(nextAns);setAnswered(true);}
      else{setSel(null);setAnswered(false);}
    }
  }
  function prev(){
    if(qi<=0)return;
    const prevQi=qi-1;
    const prevAns=answers[prevQi];
    setQi(prevQi);
    if(prevAns!==undefined){setSel(prevAns);setAnswered(true);}
    else{setSel(null);setAnswered(false);}
  }

  function handleExamAns(i){
    if(answered)return;
    setSel(i);setAnswered(true);
    setExamAnswers(prev=>({...prev,[qi]:i}));
    // 考試模式不即時更新星星
  }
  function examNext(){
    clearInterval(timerRef.current);
    setDrawerOpen(false);setDrawerNo("");
    if(qi+1>=queue.length){
      // 全部作答完畢 → 進入結算
      setMode("examDone");
    } else {
      const nextQi=qi+1;
      const nextAns=examAnswers[nextQi];
      setQi(nextQi);
      if(nextAns!==undefined){setSel(nextAns);setAnswered(true);}
      else{setSel(null);setAnswered(false);}
    }
  }
  function examPrev(){
    if(qi<=0)return;
    const prevQi=qi-1;
    const prevAns=examAnswers[prevQi];
    setQi(prevQi);
    if(prevAns!==undefined){setSel(prevAns);setAnswered(true);}
    else{setSel(null);setAnswered(false);}
  }
  function openDrawer(){
    const cfg=LAW_CONFIG[cq?.subject];
    if(cfg)setDrawerLaw(cfg);
    setDrawerOpen(true);
  }
  function handleDrawerQuery(){
    const no=drawerNo.trim();
    if(!no)return;
    if(drawerLaw&&drawerLaw.pcode){
      window.open(getLawUrl(drawerLaw.pcode,no),"_blank","noopener");
    }else if(drawerLawInput.trim()){
      const kw=drawerLawInput.trim();
      window.open(`https://law.moj.gov.tw/LawClass/LawSearchContent.aspx?pc=&tf=${encodeURIComponent(kw)}&ta=${encodeURIComponent(no)}&TY=04`,"_blank","noopener");
    }
  }
  const practiced=Object.keys(prog).length;
  const mastered=Object.values(prog).filter(p=>p.stars?.every(v=>v==="g")).length;
  const totalQ=ALL_Q.length;
  const customCount=customQ.length;

  // 匯入處理
  function handleImport(){
    setImportErr("");setImportOk("");
    let parsed;
    try{ parsed=JSON.parse(importText.trim()); }
    catch{ setImportErr("JSON 格式錯誤，請檢查括號與引號是否正確。");return; }
    if(!Array.isArray(parsed)){setImportErr("頂層必須是陣列 [ ... ]");return;}
    if(parsed.length===0){setImportErr("陣列為空，請至少包含一題。");return;}
    // 驗證每題
    for(let i=0;i<parsed.length;i++){
      const err=validateQ(parsed[i],i);
      if(err){setImportErr(err);return;}
    }
    // 去重：過濾掉已存在於 QB 的 id
    const builtinIds=new Set(QB.map(q=>q.id));
    const newQ=parsed.filter(q=>!builtinIds.has(q.id));
    // 合併：覆蓋已有自訂題（同 id）
    const existingIds=new Set(customQ.map(q=>q.id));
    const merged=[...customQ.filter(q=>!parsed.some(p=>p.id===q.id)),...newQ];
    setCustomQ(merged);
    saveCustom(merged);
    const added=newQ.filter(q=>!existingIds.has(q.id)).length;
    const updated=newQ.filter(q=>existingIds.has(q.id)).length;
    setImportOk(`匯入成功！新增 ${added} 題${updated?`、更新 ${updated} 題`:""}。`);
    setImportText("");
  }

  function handleDeleteCustom(){
    if(!confirm(`確定刪除全部 ${customQ.length} 道自訂題目？`))return;
    setCustomQ([]);saveCustom([]);
  }

  // pill button
  const Pill=({label,active,onClick})=>(
    <button onClick={onClick} style={{padding:"0.3rem 0.75rem",borderRadius:100,border:`1.5px solid ${active?T.navy:T.bdr}`,background:active?T.navy:"transparent",color:active?"#fff":T.ink,fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit",transition:"all 0.12s",whiteSpace:"nowrap"}}>
      {label}
    </button>
  );
  // 考試篩選用多選 Pill（金色調）
  const ExamPill=({label,active,onClick})=>(
    <button onClick={onClick} style={{padding:"0.3rem 0.75rem",borderRadius:100,border:`1.5px solid ${active?T.gold:"#e2ddd5"}`,background:active?T.goldBg:"transparent",color:active?T.gold:T.muted,fontSize:"0.78rem",cursor:"pointer",fontFamily:"inherit",transition:"all 0.12s",whiteSpace:"nowrap",fontWeight:active?700:400}}>
      {label}
    </button>
  );

  const isMobile=typeof window!=="undefined"&&window.innerWidth<640;
  const card={background:T.white,borderRadius:16,padding:"1.25rem",boxShadow:"0 2px 18px rgba(22,33,62,0.06)",border:`1px solid ${T.bdr}`,marginTop:"0.75rem"};

  return(
    <div style={{fontFamily:"'Noto Serif TC','Georgia',serif",background:T.bg,minHeight:"100vh",color:T.ink}}>
      {/* header */}
      <header style={{background:T.navy,padding:"0.875rem 1.125rem",position:"sticky",top:0,zIndex:20,boxShadow:"0 3px 18px rgba(0,0,0,0.28)"}}>
        <div style={{maxWidth:660,margin:"0 auto",display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <div>
            <div style={{fontSize:"0.58rem",letterSpacing:"0.14em",color:T.accent,textTransform:"uppercase",fontFamily:"Arial,sans-serif",marginBottom:2}}>
              {[cat,yr].filter(v=>v!=="全部").join("・") || "國家考試題庫練習"}
            </div>
            <h1 style={{margin:0,fontSize:"1.15rem",fontWeight:700,color:"#fff",letterSpacing:"0.02em"}}>法律練功房 <span style={{fontSize:"0.65rem",fontWeight:400,opacity:0.6,fontFamily:"Arial,sans-serif"}}>v14</span></h1>
          </div>
          <div style={{display:"flex",gap:"0.4rem"}}>
            {[{n:mastered,l:"精熟"},{n:practiced,l:"練習"},{n:totalQ,l:"題數"}].map(({n,l})=>(
              <div key={l} style={{background:"rgba(255,255,255,0.1)",borderRadius:8,padding:"0.22rem 0.55rem",textAlign:"center",minWidth:40}}>
                <span style={{display:"block",fontSize:"0.9rem",fontWeight:700,color:T.accent,lineHeight:1.1}}>{n}</span>
                <span style={{display:"block",fontSize:"0.56rem",color:"#aaa",fontFamily:"Arial,sans-serif"}}>{l}</span>
              </div>
            ))}
          </div>
        </div>
      </header>

      <main style={{maxWidth:660,margin:"0 auto",padding:"0.875rem 0.875rem 4rem"}}>

        {/* ── 篩選 ── */}
        {mode==="filter"&&(
          <div style={card}>
            <h2 style={{margin:"0 0 0.875rem",fontSize:"0.97rem",fontWeight:700,color:T.navy,borderBottom:`2px solid ${T.bdr}`,paddingBottom:"0.5rem"}}>選擇出題範圍</h2>

            {/* 考試類組 */}
            <div style={{marginBottom:"0.875rem"}}>
              <label style={{display:"block",fontSize:"0.65rem",fontWeight:600,color:T.muted,marginBottom:"0.35rem",fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase"}}>考試類組</label>
              <div style={{display:"flex",flexWrap:"wrap",gap:"0.35rem"}}>
                {ALL_CATEGORIES.map(c=>(
                  <Pill key={c} label={c} active={cat===c} onClick={()=>{setCat(c);setYr("全部");setGrp("全部");setSubj("全部");}}/>
                ))}
              </div>
            </div>

            {/* 年度 */}
            <div style={{marginBottom:"0.875rem"}}>
              <label style={{display:"block",fontSize:"0.65rem",fontWeight:600,color:T.muted,marginBottom:"0.35rem",fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase"}}>年度</label>
              <div style={{display:"flex",flexWrap:"wrap",gap:"0.35rem"}}>
                {years.map(y=>(
                  <Pill key={y} label={y} active={yr===y} onClick={()=>{setYr(y);setGrp("全部");setSubj("全部");}}/>
                ))}
              </div>
            </div>

            {/* 考試別 */}
            <div style={{marginBottom:"0.875rem"}}>
              <label style={{display:"block",fontSize:"0.65rem",fontWeight:600,color:T.muted,marginBottom:"0.35rem",fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase"}}>考試別</label>
              <div style={{display:"flex",flexWrap:"wrap",gap:"0.35rem"}}>
                {groups.map(g=><Pill key={g} label={g} active={grp===g} onClick={()=>{setGrp(g);setSubj("全部");}}/>)}
              </div>
            </div>

            <div style={{marginBottom:"0.875rem"}}>
              <label style={{display:"block",fontSize:"0.65rem",fontWeight:600,color:T.muted,marginBottom:"0.35rem",fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase"}}>科目</label>
              <div style={{display:"flex",flexWrap:"wrap",gap:"0.35rem"}}>
                {subjects.map(s=><Pill key={s} label={s} active={subj===s} onClick={()=>setSubj(s)}/>)}
              </div>
            </div>

            <div style={{fontSize:"0.78rem",color:T.muted,marginBottom:"0.875rem",fontFamily:"Arial,sans-serif"}}>符合條件：<strong style={{color:T.ink}}>{filtered.length}</strong> 題{customCount>0&&<span style={{marginLeft:"0.4rem",color:T.gold}}>（含自訂 {customCount} 題）</span>}</div>

            {/* 科目進度統計 */}
            {Object.keys(subjectStats).length>0&&(
              <div style={{background:"#f8f7f4",borderRadius:12,padding:"0.75rem 0.9rem",marginBottom:"0.875rem",border:`1px solid ${T.bdr}`}}>
                <div style={{fontSize:"0.65rem",fontWeight:600,color:T.muted,letterSpacing:"0.07em",textTransform:"uppercase",fontFamily:"Arial,sans-serif",marginBottom:"0.55rem"}}>各科進度</div>
                {Object.entries(subjectStats).map(([s,{total,mastered,practiced}])=>(
                  <div key={s} style={{marginBottom:"0.45rem"}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"0.18rem"}}>
                      <span style={{fontSize:"0.76rem",color:T.ink}}>{s}</span>
                      <span style={{fontSize:"0.7rem",color:T.muted,fontFamily:"Arial,sans-serif"}}>
                        精熟 <strong style={{color:T.gold}}>{mastered}</strong> / 練習 <strong style={{color:T.blue}}>{practiced}</strong> / 共 {total}
                      </span>
                    </div>
                    <div style={{height:5,background:T.bdr,borderRadius:4,overflow:"hidden",display:"flex"}}>
                      <div style={{width:`${mastered/total*100}%`,background:T.accent,transition:"width 0.4s"}}/>
                      <div style={{width:`${(practiced-mastered)/total*100}%`,background:"#93c5fd",transition:"width 0.4s"}}/>
                    </div>
                  </div>
                ))}
                <div style={{display:"flex",gap:"0.75rem",marginTop:"0.5rem",fontSize:"0.66rem",color:T.muted,fontFamily:"Arial,sans-serif"}}>
                  <span><span style={{color:T.accent}}>■</span> 精熟</span><span><span style={{color:"#93c5fd"}}>■</span> 已練習</span><span><span style={{color:T.bdr}}>■</span> 未練習</span>
                </div>
              </div>
            )}

            {/* 繼續測驗（僅在有未完成輪次時顯示） */}
            {sessionExists&&(
              <button onClick={continueSession} style={{width:"100%",marginBottom:"0.5rem",padding:"0.85rem",background:T.accent,color:"#fff",border:"none",borderRadius:12,fontSize:"0.95rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit",letterSpacing:"0.02em"}}>
                ▶ 繼續上次測驗
              </button>
            )}

            {/* 開始練習 */}
            <button onClick={start} disabled={!filtered.length} style={{width:"100%",padding:"0.85rem",background:filtered.length?T.navy:"#ccc",color:"#fff",border:"none",borderRadius:12,fontSize:"0.95rem",fontWeight:700,cursor:filtered.length?"pointer":"not-allowed",fontFamily:"inherit"}}>
              開始練習 →
            </button>

            {/* 錯題複習 & 書籤練習 */}
            <div style={{display:"flex",gap:"0.5rem",marginTop:"0.5rem"}}>
              <button onClick={startMistake} disabled={!mistakeQs.length} style={{flex:1,padding:"0.62rem",background:mistakeQs.length?"#fef2f2":"#f5f5f5",color:mistakeQs.length?T.red:"#aaa",border:`1.5px solid ${mistakeQs.length?"#fca5a5":"#e5e5e5"}`,borderRadius:12,fontSize:"0.82rem",fontWeight:600,cursor:mistakeQs.length?"pointer":"not-allowed",fontFamily:"inherit"}}>
                ✦ 錯題複習 {mistakeQs.length>0&&`(${mistakeQs.length})`}
              </button>
              <button onClick={startBookmark} disabled={!bookmarkQs.length} style={{flex:1,padding:"0.62rem",background:bookmarkQs.length?"#fef9ec":"#f5f5f5",color:bookmarkQs.length?T.gold:"#aaa",border:`1.5px solid ${bookmarkQs.length?"#fde68a":"#e5e5e5"}`,borderRadius:12,fontSize:"0.82rem",fontWeight:600,cursor:bookmarkQs.length?"pointer":"not-allowed",fontFamily:"inherit"}}>
                ◈ 書籤練習 {bookmarkQs.length>0&&`(${bookmarkQs.length})`}
              </button>
            </div>

            {/* 考試模式 */}
            <button onClick={()=>setMode("examSetup")} disabled={!filtered.length} style={{width:"100%",marginTop:"0.5rem",padding:"0.72rem",background:filtered.length?"#1e3a5f":"#ccc",color:"#fff",border:"none",borderRadius:12,fontSize:"0.88rem",fontWeight:600,cursor:filtered.length?"pointer":"not-allowed",fontFamily:"inherit",letterSpacing:"0.03em"}}>
              ✦ 考試模式（設定範圍）
            </button>

            {/* 匯入按鈕 */}
            <button onClick={()=>{setShowImport(true);setImportErr("");setImportOk("");}} style={{width:"100%",marginTop:"0.5rem",padding:"0.62rem",background:"transparent",color:T.blue,border:`1.5px solid ${T.blue}`,borderRadius:12,fontSize:"0.85rem",fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>
              ＋ 匯入自訂題目
            </button>

            {/* 題庫總覽 */}
            <div style={{marginTop:"1.25rem",borderTop:`1px solid ${T.bdr}`,paddingTop:"0.875rem"}}>
              <div style={{fontSize:"0.68rem",color:T.muted,fontFamily:"Arial,sans-serif",letterSpacing:"0.09em",textTransform:"uppercase",marginBottom:"0.6rem"}}>
                題庫總覽（{filtered.length} / {totalQ} 題）
              </div>
              {filtered.map(q=>{
                const stars=getStars(prog,q.id);
                const isCustom=!QB.find(b=>b.id===q.id);
                return(
                  <div key={q.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"0.4rem 0",borderBottom:`1px solid ${T.bdr}`,gap:"0.4rem"}}>
                    <div style={{display:"flex",alignItems:"center",gap:"0.3rem",flex:1,overflow:"hidden"}}>
                      {isCustom&&<span style={{fontSize:"0.56rem",background:"#e0f2fe",color:"#0369a1",borderRadius:4,padding:"0.06rem 0.28rem",fontFamily:"Arial,sans-serif",whiteSpace:"nowrap",flexShrink:0,border:"1px solid #7dd3fc",fontWeight:700}}>自訂</span>}
                      <span style={{fontSize:"0.56rem",background:"#f3e8ff",color:"#7e22ce",borderRadius:4,padding:"0.06rem 0.28rem",fontFamily:"Arial,sans-serif",whiteSpace:"nowrap",flexShrink:0,border:"1px solid #d8b4fe"}}>{q.examCategory}</span>
                      <span style={{fontSize:"0.58rem",background:T.goldBg,color:T.gold,borderRadius:4,padding:"0.06rem 0.28rem",fontFamily:"Arial,sans-serif",whiteSpace:"nowrap",flexShrink:0,border:`1px solid #f0d080`}}>{q.year}</span>
                      <span style={{fontSize:"0.6rem",background:T.blueBg,color:T.blue,borderRadius:4,padding:"0.06rem 0.28rem",fontFamily:"Arial,sans-serif",whiteSpace:"nowrap",flexShrink:0}}>{q.subject}</span>
                      <span style={{fontSize:"0.72rem",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",flex:1}}>{q.text.slice(0,24)}…</span>
                    </div>
                    <div style={{display:"flex",gap:1,flexShrink:0}}>{stars.map((t,i)=><Star key={i} t={t}/>)}</div>
                  </div>
                );
              })}
              <div style={{display:"flex",gap:"0.5rem",marginTop:"0.75rem"}}>
                {customCount>0&&(
                  <button onClick={handleDeleteCustom} style={{flex:1,padding:"0.5rem",background:"transparent",color:"#0369a1",border:`1.5px solid #7dd3fc`,borderRadius:10,fontSize:"0.76rem",cursor:"pointer",fontFamily:"inherit"}}>— 刪除自訂題（{customCount}）</button>
                )}
                <button onClick={()=>{if(confirm("確定清除所有作答進度？")){localStorage.removeItem(LS);setProg({});}}} style={{flex:1,padding:"0.5rem",background:"transparent",color:T.red,border:`1.5px solid #fca5a5`,borderRadius:10,fontSize:"0.76rem",cursor:"pointer",fontFamily:"inherit"}}>— 清除作答進度</button>
              </div>
            </div>
          </div>
        )}

        {/* ── 考試模式設定 ── */}
        {mode==="examSetup"&&(
          <div style={card}>
            <div style={{display:"flex",alignItems:"center",justifyContent:"space-between",marginBottom:"0.875rem",borderBottom:`2px solid ${T.bdr}`,paddingBottom:"0.5rem"}}>
              <h2 style={{margin:0,fontSize:"0.97rem",fontWeight:700,color:T.navy}}>考試模式 — 設定範圍</h2>
              <button onClick={()=>setMode("filter")} style={{background:"none",border:"none",color:T.muted,fontSize:"0.82rem",cursor:"pointer",fontFamily:"inherit",padding:"0.2rem 0.4rem"}}>← 返回</button>
            </div>
            <p style={{fontSize:"0.78rem",color:T.muted,margin:"0 0 0.875rem",fontFamily:"Arial,sans-serif",lineHeight:1.6}}>不選擇代表全部納入。從符合條件的題目中隨機抽取最多 75 題，作答時不顯示對錯，完成後一次結算。</p>

            {/* 考試類組（多選）*/}
            <div style={{marginBottom:"0.875rem"}}>
              <label style={{display:"block",fontSize:"0.65rem",fontWeight:600,color:T.muted,marginBottom:"0.35rem",fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase"}}>考試類組</label>
              <div style={{display:"flex",flexWrap:"wrap",gap:"0.35rem"}}>
                {ALL_CAT_OPTS.map(c=>(
                  <ExamPill key={c} label={c} active={exCats.has(c)}
                    onClick={()=>toggleSet(setExCats,c)}/>
                ))}
              </div>
            </div>

            {/* 年度（多選）*/}
            <div style={{marginBottom:"0.875rem"}}>
              <label style={{display:"block",fontSize:"0.65rem",fontWeight:600,color:T.muted,marginBottom:"0.35rem",fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase"}}>年度</label>
              <div style={{display:"flex",flexWrap:"wrap",gap:"0.35rem"}}>
                {exYearOpts.map(y=>(
                  <ExamPill key={y} label={y} active={exYrs.has(y)}
                    onClick={()=>toggleSet(setExYrs,y)}/>
                ))}
              </div>
            </div>

            {/* 考試別（多選）*/}
            <div style={{marginBottom:"0.875rem"}}>
              <label style={{display:"block",fontSize:"0.65rem",fontWeight:600,color:T.muted,marginBottom:"0.35rem",fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase"}}>考試別</label>
              <div style={{display:"flex",flexWrap:"wrap",gap:"0.35rem"}}>
                {exGrpOpts.map(g=>(
                  <ExamPill key={g} label={g} active={exGrps.has(g)}
                    onClick={()=>toggleSet(setExGrps,g)}/>
                ))}
              </div>
            </div>

            {/* 科目（多選）*/}
            <div style={{marginBottom:"0.875rem"}}>
              <label style={{display:"block",fontSize:"0.65rem",fontWeight:600,color:T.muted,marginBottom:"0.35rem",fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase"}}>科目</label>
              <div style={{display:"flex",flexWrap:"wrap",gap:"0.35rem"}}>
                {exSubjOpts.map(s=>(
                  <ExamPill key={s} label={s} active={exSubjs.has(s)}
                    onClick={()=>toggleSet(setExSubjs,s)}/>
                ))}
              </div>
            </div>

            <div style={{fontSize:"0.78rem",color:T.muted,marginBottom:"0.875rem",fontFamily:"Arial,sans-serif"}}>
              符合條件：<strong style={{color:T.ink}}>{examFiltered.length}</strong> 題，
              將隨機抽取 <strong style={{color:T.navy}}>{Math.min(examFiltered.length,75)}</strong> 題
              <span style={{marginLeft:"0.4rem",color:T.gold}}>（{Math.min(examFiltered.length,75)*2} 分滿分）</span>
            </div>

            <button onClick={startExam} disabled={!examFiltered.length} style={{width:"100%",padding:"0.85rem",background:examFiltered.length?"#1e3a5f":"#ccc",color:"#fff",border:"none",borderRadius:12,fontSize:"0.95rem",fontWeight:700,cursor:examFiltered.length?"pointer":"not-allowed",fontFamily:"inherit",letterSpacing:"0.03em"}}>
              開始考試 →
            </button>
          </div>
        )}

        {/* ── 作答 ── */}
        {mode==="quiz"&&cq&&(
          <div>
            <div style={{marginTop:"0.75rem"}}>
              <div style={{height:4,background:T.bdr,borderRadius:4,overflow:"hidden"}}>
                <div style={{height:"100%",background:T.navy,borderRadius:4,width:`${(qi+1)/queue.length*100}%`,transition:"width 0.3s"}}/>
              </div>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:"0.2rem"}}>
                <div style={{fontSize:"0.66rem",color:T.muted,fontFamily:"Arial,sans-serif"}}>第 {qi+1} / {queue.length} 題</div>
                <div style={{fontSize:"0.66rem",fontFamily:"monospace",color:answered?"#94a3b8":qTimer>=60?T.red:qTimer>=30?"#d97706":T.muted,fontWeight:600}}>
                  ◷ {fmtTime(qTimer)}
                </div>
              </div>
            </div>
            <div style={card}>
              {/* meta */}
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"0.75rem"}}>
                <div style={{display:"flex",gap:2,alignItems:"center"}}>
                  {getStars(prog,cq.id).map((t,i)=><Star key={i} t={t}/>)}
                </div>
                <div style={{display:"flex",gap:"0.3rem",alignItems:"center",flexWrap:"wrap",justifyContent:"flex-end"}}>
                  <button onClick={openDrawer} style={{padding:"0.22rem 0.6rem",fontSize:"0.65rem",background:"#1a56db",color:"#fff",border:"none",borderRadius:4,cursor:"pointer",fontFamily:"Arial,sans-serif",fontWeight:700,letterSpacing:"0.04em"}}>條文</button>
                  <button onClick={()=>toggleBookmark(cq.id)} title={bookmarks.has(cq.id)?"取消書籤":"加入書籤"} style={{background:"none",border:"none",cursor:"pointer",fontSize:"1.1rem",padding:"0 0.1rem",lineHeight:1,opacity:bookmarks.has(cq.id)?1:0.35,transition:"opacity 0.15s"}}>◈</button>
                  <span style={{fontSize:"0.58rem",background:"#f3e8ff",color:"#7e22ce",borderRadius:4,padding:"0.08rem 0.35rem",fontFamily:"Arial,sans-serif",border:"1px solid #d8b4fe"}}>{cq.examCategory}</span>
                  <span style={{fontSize:"0.6rem",background:T.goldBg,color:T.gold,borderRadius:4,padding:"0.08rem 0.35rem",fontFamily:"Arial,sans-serif",border:`1px solid #f0d080`}}>{cq.year}</span>
                  <span style={{fontSize:"0.6rem",background:T.blueBg,color:T.blue,borderRadius:4,padding:"0.08rem 0.35rem",fontFamily:"Arial,sans-serif"}}>{cq.subject}</span>
                </div>
              </div>
              <p style={{fontSize:"0.93rem",lineHeight:1.82,color:T.navy,margin:"0 0 0.95rem",fontWeight:500}}>{cq.text}</p>

              {/* options */}
              <div style={{display:"flex",flexDirection:"column",gap:"0.44rem"}}>
                {cq.options.map((opt,i)=>{
                  let bg="#f9f8f5",bdr=T.bdr,clr=T.ink,fw=400;
                  if(answered){
                    if(i===cq.answer){bg=T.greenBg;bdr="#86efac";clr=T.green;fw=600;}
                    else if(i===sel){bg=T.redBg;bdr="#fca5a5";clr=T.red;fw=600;}
                  }
                  const dimmed=answered&&i!==cq.answer&&i!==sel;
                  return(
                    <button key={i} onClick={()=>handleAns(i)} disabled={answered} style={{display:"flex",alignItems:"flex-start",gap:"0.62rem",padding:"0.78rem 0.9rem",background:bg,border:`1.5px solid ${bdr}`,borderRadius:12,textAlign:"left",cursor:answered?"default":"pointer",fontFamily:"inherit",fontSize:"0.87rem",color:clr,fontWeight:fw,lineHeight:1.58,width:"100%",boxSizing:"border-box",opacity:dimmed?0.35:1,transition:"all 0.12s"}}>
                      <span style={{display:"inline-flex",alignItems:"center",justifyContent:"center",width:22,height:22,borderRadius:"50%",background:answered&&i===cq.answer?"#166534":answered&&i===sel?"#991b1b":T.bdr,color:answered&&(i===cq.answer||i===sel)?"#fff":T.navy,fontSize:"0.67rem",fontWeight:700,flexShrink:0,fontFamily:"Arial,sans-serif",marginTop:2}}>{["A","B","C","D"][i]}</span>
                      <span style={{flex:1}}>{opt}</span>
                    </button>
                  );
                })}
              </div>

              {answered&&(
                <div style={{marginTop:"0.85rem",borderRadius:10,padding:"0.7rem 0.875rem",fontSize:"0.82rem",lineHeight:1.72,background:sel===cq.answer?T.greenBg:T.redBg,border:`1px solid ${sel===cq.answer?"#86efac":"#fca5a5"}`}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"0.2rem"}}>
                    <div style={{display:"flex",alignItems:"center",gap:"0.4rem"}}>
                      <span style={{fontWeight:700,fontSize:"0.86rem",color:sel===cq.answer?T.green:T.red}}>{sel===cq.answer?"✓ 答對了！":"✗ 答錯了"}</span>
                      {answers[qi]!==undefined&&qi>0&&<span style={{fontSize:"0.66rem",color:T.muted,fontFamily:"Arial,sans-serif"}}>（重新查看）</span>}
                    </div>
                    <div style={{fontSize:"0.7rem",color:T.muted,fontFamily:"monospace"}}>◷ {fmtTime(qTimer)}</div>
                  </div>
                  <div style={{color:T.ink}}>{cq.explanation}</div>
                </div>
              )}

              <div style={{display:"flex",gap:"0.4rem",marginTop:"0.875rem",flexWrap:"wrap"}}>
                <button onClick={goHome} style={{padding:"0.72rem 0.9rem",background:"transparent",color:T.muted,border:`1.5px solid ${T.bdr}`,borderRadius:12,fontSize:"0.82rem",cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>首頁</button>
                {qi>0&&(
                  <button onClick={prev} style={{flex:1,padding:"0.72rem",background:"transparent",color:T.ink,border:`1.5px solid ${T.bdr}`,borderRadius:12,fontSize:"0.87rem",cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>← 上一題</button>
                )}
                {answered
                  ?<button onClick={next} style={{flex:2,padding:"0.72rem",background:T.navy,color:"#fff",border:"none",borderRadius:12,fontSize:"0.87rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>{qi+1>=queue.length?"查看結果 →":"下一題 →"}</button>
                  :<div style={{flex:2}}/>
                }
              </div>
            </div>
          </div>
        )}

        {/* ── 完成 ── */}
        {mode==="done"&&(
          <div style={card}>
            <div style={{fontSize:"1.4rem",textAlign:"center",marginBottom:"0.4rem",letterSpacing:"0.1em",color:T.navy,fontWeight:300}}>✦ ✦ ✦</div>
            <h2 style={{textAlign:"center",fontSize:"1.2rem",fontWeight:700,margin:"0 0 0.2rem"}}>本輪完成</h2>
            <div style={{display:"flex",justifyContent:"center",gap:"1.5rem",margin:"0 0 1.1rem"}}>
              <div style={{textAlign:"center"}}>
                <div style={{fontSize:"0.65rem",color:T.muted,fontFamily:"Arial,sans-serif",letterSpacing:"0.06em",textTransform:"uppercase"}}>作答題數</div>
                <div style={{fontSize:"1.1rem",fontWeight:700,color:T.navy}}>{queue.length}</div>
              </div>
              <div style={{textAlign:"center"}}>
                <div style={{fontSize:"0.65rem",color:T.muted,fontFamily:"Arial,sans-serif",letterSpacing:"0.06em",textTransform:"uppercase"}}>總作答時長</div>
                <div style={{fontSize:"1.1rem",fontWeight:700,color:T.navy}}>◷ {fmtTime(totalElapsed)}</div>
              </div>
            </div>
            <div style={{marginBottom:"1rem",maxHeight:"50vh",overflow:"auto"}}>
              {queue.map(q=>{
                const isWrong=prog[q.id]?.stars.some(s=>s==="r");
                const isBookmarked=bookmarks.has(q.id);
                return(
                  <div key={q.id} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"0.4rem 0",borderBottom:`1px solid ${T.bdr}`,gap:"0.35rem"}}>
                    <div style={{display:"flex",alignItems:"center",gap:"0.3rem",flex:1,overflow:"hidden"}}>
                      <span style={{fontSize:"0.6rem",background:T.blueBg,color:T.blue,borderRadius:4,padding:"0.08rem 0.3rem",fontFamily:"Arial,sans-serif",whiteSpace:"nowrap",flexShrink:0}}>{q.subject}</span>
                      <span style={{fontSize:"0.76rem",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",flex:1}}>{q.text.slice(0,24)}…</span>
                    </div>
                    <div style={{display:"flex",alignItems:"center",gap:"0.35rem",flexShrink:0}}>
                      <button onClick={()=>toggleBookmark(q.id)} style={{background:"none",border:"none",cursor:"pointer",fontSize:"0.95rem",padding:0,opacity:isBookmarked?1:0.3,lineHeight:1}}>◈</button>
                      <div style={{display:"flex",gap:1}}>{getStars(prog,q.id).map((t,i)=><Star key={i} t={t}/>)}</div>
                    </div>
                  </div>
                );
              })}
            </div>
            <div style={{display:"flex",gap:"0.5rem"}}>
              <button onClick={()=>setMode("filter")} style={{flex:1,padding:"0.72rem",background:"transparent",color:T.ink,border:`1.5px solid ${T.bdr}`,borderRadius:12,fontSize:"0.87rem",cursor:"pointer",fontFamily:"inherit"}}>← 回首頁</button>
              <button onClick={()=>{clearSession();setSessionExists(false);totalElapsedRef.current=0;setTotalElapsed(0);start();}} style={{flex:2,padding:"0.72rem",background:T.navy,color:"#fff",border:"none",borderRadius:12,fontSize:"0.87rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>再練一輪 →</button>
            </div>
          </div>
        )}
        {/* ── 考試作答 ── */}
        {mode==="exam"&&cq&&(
          <div>
            <div style={{marginTop:"0.75rem"}}>
              <div style={{height:4,background:T.bdr,borderRadius:4,overflow:"hidden"}}>
                <div style={{height:"100%",background:"#1e3a5f",borderRadius:4,width:`${(qi+1)/queue.length*100}%`,transition:"width 0.3s"}}/>
              </div>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:"0.2rem"}}>
                <div style={{fontSize:"0.66rem",color:T.muted,fontFamily:"Arial,sans-serif"}}>
                  第 {qi+1} / {queue.length} 題
                  {Object.keys(examAnswers).length>0&&<span style={{marginLeft:"0.5rem",color:T.accent}}>已作答 {Object.keys(examAnswers).length} 題</span>}
                </div>
                <div style={{fontSize:"0.62rem",fontFamily:"Arial,sans-serif",color:T.muted,letterSpacing:"0.05em"}}>考試模式</div>
              </div>
            </div>
            <div style={card}>
              {/* meta */}
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"0.75rem"}}>
                <div style={{fontSize:"0.72rem",color:T.muted,fontFamily:"Arial,sans-serif"}}>{cq.subject}</div>
                <div style={{display:"flex",gap:"0.3rem",alignItems:"center"}}>
                  <button onClick={openDrawer} style={{padding:"0.22rem 0.6rem",fontSize:"0.65rem",background:"#1a56db",color:"#fff",border:"none",borderRadius:4,cursor:"pointer",fontFamily:"Arial,sans-serif",fontWeight:700,letterSpacing:"0.04em"}}>條文</button>
                  <span style={{fontSize:"0.58rem",background:T.goldBg,color:T.gold,borderRadius:4,padding:"0.06rem 0.28rem",fontFamily:"Arial,sans-serif",border:`1px solid #f0d080`}}>{cq.year}</span>
                  <span style={{fontSize:"0.58rem",background:"#f3e8ff",color:"#7e22ce",borderRadius:4,padding:"0.06rem 0.28rem",fontFamily:"Arial,sans-serif",border:"1px solid #d8b4fe"}}>{cq.examCategory}</span>
                </div>
              </div>
              <p style={{fontSize:"0.93rem",lineHeight:1.82,color:T.navy,margin:"0 0 0.95rem",fontWeight:500}}>{cq.text}</p>

              {/* 選項（考試模式：不顯示對錯色彩，只標記已選） */}
              <div style={{display:"flex",flexDirection:"column",gap:"0.44rem"}}>
                {cq.options.map((opt,i)=>{
                  const isSelected=sel===i;
                  return(
                    <button key={i} onClick={()=>handleExamAns(i)} disabled={answered} style={{display:"flex",alignItems:"flex-start",gap:"0.62rem",padding:"0.78rem 0.9rem",background:isSelected?"#e8edf5":"#f9f8f5",border:`1.5px solid ${isSelected?"#1e3a5f":T.bdr}`,borderRadius:12,textAlign:"left",cursor:answered?"default":"pointer",fontFamily:"inherit",fontSize:"0.87rem",color:isSelected?"#1e3a5f":T.ink,fontWeight:isSelected?600:400,lineHeight:1.58,width:"100%",boxSizing:"border-box",transition:"all 0.12s"}}>
                      <span style={{display:"inline-flex",alignItems:"center",justifyContent:"center",width:22,height:22,borderRadius:"50%",background:isSelected?"#1e3a5f":T.bdr,color:isSelected?"#fff":T.navy,fontSize:"0.67rem",fontWeight:700,flexShrink:0,fontFamily:"Arial,sans-serif",marginTop:2}}>{["A","B","C","D"][i]}</span>
                      <span style={{flex:1}}>{opt}</span>
                    </button>
                  );
                })}
              </div>

              {/* 已選但不揭曉 */}
              {answered&&(
                <div style={{marginTop:"0.75rem",padding:"0.6rem 0.875rem",borderRadius:8,background:"#f0f4f8",border:`1px solid #c8d5e0`,fontSize:"0.78rem",color:T.muted,fontFamily:"Arial,sans-serif"}}>
                  已記錄選擇，結束後一次公布結果。
                </div>
              )}

              <div style={{display:"flex",gap:"0.4rem",marginTop:"0.875rem",flexWrap:"wrap"}}>
                <button onClick={goHomeFromExam} style={{padding:"0.72rem 0.9rem",background:"transparent",color:T.muted,border:`1.5px solid ${T.bdr}`,borderRadius:12,fontSize:"0.82rem",cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>首頁</button>
                {qi>0&&(
                  <button onClick={examPrev} style={{flex:1,padding:"0.72rem",background:"transparent",color:T.ink,border:`1.5px solid ${T.bdr}`,borderRadius:12,fontSize:"0.87rem",cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>← 上一題</button>
                )}
                {answered
                  ?<button onClick={examNext} style={{flex:2,padding:"0.72rem",background:"#1e3a5f",color:"#fff",border:"none",borderRadius:12,fontSize:"0.87rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap"}}>{qi+1>=queue.length?"交卷 →":"下一題 →"}</button>
                  :<div style={{flex:2}}/>
                }
              </div>
            </div>
          </div>
        )}

        {/* ── 考試結算 ── */}
        {mode==="examDone"&&(()=>{
          const totalQ=queue.length;
          const scorePerQ=2;
          let correct=0;
          const bySubject={};
          queue.forEach((q,i)=>{
            const ans=examAnswers[i];
            const isCorrect=ans===q.answer;
            if(isCorrect)correct++;
            if(!bySubject[q.subject])bySubject[q.subject]={total:0,correct:0};
            bySubject[q.subject].total++;
            if(isCorrect)bySubject[q.subject].correct++;
          });
          const totalScore=correct*scorePerQ;
          const fullScore=totalQ*scorePerQ;
          const pct=Math.round(correct/totalQ*100);
          return(
            <div style={card}>
              <div style={{textAlign:"center",marginBottom:"1.1rem",paddingBottom:"0.875rem",borderBottom:`1px solid ${T.bdr}`}}>
                <div style={{fontSize:"0.65rem",letterSpacing:"0.12em",textTransform:"uppercase",color:T.muted,fontFamily:"Arial,sans-serif",marginBottom:"0.3rem"}}>考試結算</div>
                <div style={{fontSize:"2.8rem",fontWeight:700,color:"#1e3a5f",lineHeight:1,marginBottom:"0.2rem"}}>{totalScore}</div>
                <div style={{fontSize:"0.82rem",color:T.muted,fontFamily:"Arial,sans-serif"}}>/ {fullScore} 分 &ensp;·&ensp; 答對 {correct} / {totalQ} 題 &ensp;·&ensp; 正確率 {pct}%</div>
                <div style={{fontSize:"0.72rem",color:T.muted,fontFamily:"Arial,sans-serif",marginTop:"0.2rem"}}>◷ 作答時長 {fmtTime(totalElapsed)}</div>
              </div>

              {/* 各科得分 */}
              <div style={{marginBottom:"1rem"}}>
                <div style={{fontSize:"0.65rem",color:T.muted,fontFamily:"Arial,sans-serif",letterSpacing:"0.08em",textTransform:"uppercase",marginBottom:"0.5rem"}}>各科成績</div>
                {Object.entries(bySubject).map(([subj,{total,correct:c}])=>(
                  <div key={subj} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"0.35rem 0",borderBottom:`1px solid ${T.bdr}`}}>
                    <span style={{fontSize:"0.82rem",color:T.ink}}>{subj}</span>
                    <div style={{display:"flex",alignItems:"center",gap:"0.75rem"}}>
                      <span style={{fontSize:"0.76rem",color:T.muted,fontFamily:"Arial,sans-serif"}}>{c}/{total} 題</span>
                      <span style={{fontSize:"0.82rem",fontWeight:600,color:"#1e3a5f",minWidth:"2.8rem",textAlign:"right"}}>{c*scorePerQ} 分</span>
                    </div>
                  </div>
                ))}
              </div>

              {/* 每題對錯 */}
              <div style={{marginBottom:"1rem"}}>
                <div style={{fontSize:"0.65rem",color:T.muted,fontFamily:"Arial,sans-serif",letterSpacing:"0.08em",textTransform:"uppercase",marginBottom:"0.5rem"}}>逐題檢視</div>
                <div style={{maxHeight:"36vh",overflowY:"auto"}}>
                  {queue.map((q,i)=>{
                    const ans=examAnswers[i];
                    const isCorrect=ans===q.answer;
                    return(
                      <div key={q.id} style={{display:"flex",alignItems:"flex-start",gap:"0.5rem",padding:"0.45rem 0",borderBottom:`1px solid ${T.bdr}`}}>
                        <span style={{flexShrink:0,width:18,height:18,borderRadius:"50%",background:isCorrect?"#166534":"#991b1b",color:"#fff",display:"inline-flex",alignItems:"center",justifyContent:"center",fontSize:"0.6rem",fontWeight:700,marginTop:2}}>{isCorrect?"✓":"✗"}</span>
                        <div style={{flex:1,overflow:"hidden"}}>
                          <div style={{fontSize:"0.74rem",color:T.ink,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{q.text.slice(0,32)}…</div>
                          {!isCorrect&&<div style={{fontSize:"0.68rem",color:T.muted,fontFamily:"Arial,sans-serif",marginTop:"0.1rem"}}>
                            你選 {ans!==undefined?["A","B","C","D"][ans]:"未作答"} &ensp;·&ensp; 正確 {["A","B","C","D"][q.answer]}
                          </div>}
                        </div>
                        <span style={{flexShrink:0,fontSize:"0.6rem",background:T.blueBg,color:T.blue,borderRadius:4,padding:"0.06rem 0.3rem",fontFamily:"Arial,sans-serif",alignSelf:"center"}}>{q.subject}</span>
                      </div>
                    );
                  })}
                </div>
              </div>

              <div style={{display:"flex",gap:"0.5rem"}}>
                <button onClick={()=>setMode("filter")} style={{flex:1,padding:"0.72rem",background:"transparent",color:T.ink,border:`1.5px solid ${T.bdr}`,borderRadius:12,fontSize:"0.87rem",cursor:"pointer",fontFamily:"inherit"}}>← 回首頁</button>
                <button onClick={()=>{setExamAnswers({});totalElapsedRef.current=0;setTotalElapsed(0);startExam();}} style={{flex:2,padding:"0.72rem",background:"#1e3a5f",color:"#fff",border:"none",borderRadius:12,fontSize:"0.87rem",fontWeight:700,cursor:"pointer",fontFamily:"inherit"}}>再考一次 →</button>
              </div>
            </div>
          );
        })()}

      </main>

      {/* ── 法規查詢抽屜 ── */}
      {(mode==="quiz"||mode==="exam")&&cq&&(()=>{
        const drawerStyle=isMobile?{
          position:"fixed",bottom:0,left:0,right:0,
          height:"60vh",background:T.white,zIndex:200,
          display:"flex",flexDirection:"column",
          boxShadow:"0 -4px 24px rgba(0,0,0,0.14)",
          borderRadius:"16px 16px 0 0",
          transform:drawerOpen?"translateY(0)":"translateY(100%)",
          transition:"transform 0.3s ease",
        }:{
          position:"fixed",top:0,right:0,
          width:360,height:"100vh",background:T.white,zIndex:200,
          display:"flex",flexDirection:"column",
          boxShadow:"-4px 0 24px rgba(0,0,0,0.12)",
          transform:drawerOpen?"translateX(0)":"translateX(100%)",
          transition:"transform 0.3s ease",
        };
        const canQuery=(drawerLaw||drawerLawInput.trim())&&drawerNo.trim();
        return(
          <div style={drawerStyle}>
            {/* 標題列 */}
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"0.875rem 1rem",borderBottom:`1px solid ${T.bdr}`,flexShrink:0}}>
              <span style={{fontWeight:700,fontSize:"0.92rem",color:T.navy}}>法條查詢</span>
              <button onClick={()=>setDrawerOpen(false)} style={{background:"none",border:"none",fontSize:"1.2rem",cursor:"pointer",color:T.muted,padding:"0.1rem 0.25rem",lineHeight:1}}>✕</button>
            </div>
            {/* 主體 */}
            <div style={{flex:1,overflowY:"auto",padding:"0.875rem 1rem",display:"flex",flexDirection:"column",gap:"0.875rem"}}>
              {/* 快速選擇法規 */}
              <div>
                <div style={{fontSize:"0.62rem",fontWeight:600,color:T.muted,fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase",marginBottom:"0.4rem"}}>快速選擇法規</div>
                <div style={{display:"flex",gap:"0.4rem",flexWrap:"nowrap",overflowX:"auto",paddingBottom:"0.3rem",WebkitOverflowScrolling:"touch",scrollbarWidth:"none"}}>
                  {QUICK_LAWS.map(law=>{
                    const active=drawerLaw?.pcode===law.pcode;
                    return(
                      <button key={law.pcode} onClick={()=>{setDrawerLaw(law);setDrawerLawInput("");}}
                        style={{padding:"0.28rem 0.65rem",borderRadius:100,border:`1.5px solid ${active?"#1a56db":T.bdr}`,background:active?"#1a56db":"transparent",color:active?"#fff":T.ink,fontSize:"0.74rem",cursor:"pointer",fontFamily:"inherit",whiteSpace:"nowrap",fontWeight:active?700:400,flexShrink:0,transition:"all 0.12s"}}>
                        {law.name}
                      </button>
                    );
                  })}
                </div>
              </div>
              {/* 自訂法規輸入 */}
              <div>
                <div style={{fontSize:"0.62rem",fontWeight:600,color:T.muted,fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase",marginBottom:"0.4rem"}}>其他法規</div>
                <input type="text" placeholder="輸入法規名稱，如：土地法" value={drawerLawInput}
                  onChange={e=>{setDrawerLawInput(e.target.value);if(e.target.value)setDrawerLaw(null);}}
                  style={{width:"100%",padding:"0.48rem 0.7rem",borderRadius:8,border:`1.5px solid ${drawerLawInput?T.blue:T.bdr}`,fontSize:"0.83rem",fontFamily:"inherit",color:T.ink,outline:"none",boxSizing:"border-box"}}/>
                {drawerLawInput&&<div style={{fontSize:"0.67rem",color:T.muted,marginTop:"0.22rem",fontFamily:"Arial,sans-serif"}}>將透過全文搜尋比對法規名稱</div>}
              </div>
              {/* 目前選取 */}
              {(drawerLaw||drawerLawInput)&&(
                <div style={{display:"flex",alignItems:"center",gap:"0.4rem",padding:"0.38rem 0.65rem",background:T.blueBg,borderRadius:8,border:`1px solid #bfdbfe`}}>
                  <span style={{fontSize:"0.78rem",color:T.blue,fontWeight:600,flex:1}}>{drawerLaw?drawerLaw.name:drawerLawInput}</span>
                  <button onClick={()=>{setDrawerLaw(null);setDrawerLawInput("");}} style={{background:"none",border:"none",color:T.muted,cursor:"pointer",fontSize:"1rem",padding:0,lineHeight:1}}>×</button>
                </div>
              )}
              {/* 條號輸入 */}
              <div>
                <div style={{fontSize:"0.62rem",fontWeight:600,color:T.muted,fontFamily:"Arial,sans-serif",letterSpacing:"0.07em",textTransform:"uppercase",marginBottom:"0.4rem"}}>條號</div>
                <div style={{display:"flex",gap:"0.5rem"}}>
                  <input type="number" placeholder="例：184" value={drawerNo}
                    onChange={e=>setDrawerNo(e.target.value)}
                    onKeyDown={e=>{if(e.key==="Enter"&&canQuery)handleDrawerQuery();}}
                    style={{flex:1,padding:"0.48rem 0.7rem",borderRadius:8,border:`1.5px solid ${T.bdr}`,fontSize:"0.95rem",fontFamily:"inherit",color:T.ink,outline:"none",boxSizing:"border-box"}}/>
                  <button onClick={handleDrawerQuery} disabled={!canQuery}
                    style={{padding:"0.48rem 1rem",background:canQuery?"#1a56db":"#ccc",color:"#fff",border:"none",borderRadius:8,fontSize:"0.82rem",cursor:canQuery?"pointer":"not-allowed",fontFamily:"inherit",fontWeight:700,whiteSpace:"nowrap",transition:"background 0.15s"}}>前往官網查看 →</button>
                </div>
              </div>
            </div>
            {/* 底部 */}
            <div style={{padding:"0.55rem 1rem",borderTop:`1px solid ${T.bdr}`,flexShrink:0,textAlign:"center"}}>
              <span style={{fontSize:"0.66rem",color:T.muted,fontFamily:"Arial,sans-serif"}}>資料來源：</span>
              <button onClick={()=>window.open("https://law.moj.gov.tw","_blank")} style={{background:"none",border:"none",color:T.blue,fontSize:"0.66rem",cursor:"pointer",fontFamily:"Arial,sans-serif",padding:0,textDecoration:"underline"}}>law.moj.gov.tw</button>
            </div>
          </div>
        );
      })()}

      {/* ── 匯入 Modal ── */}
      {showImport&&(
        <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.55)",zIndex:100,display:"flex",alignItems:"flex-end",justifyContent:"center"}} onClick={e=>{if(e.target===e.currentTarget)setShowImport(false);}}>
          <div style={{background:T.white,borderRadius:"18px 18px 0 0",padding:"1.25rem 1.125rem 2rem",width:"100%",maxWidth:660,maxHeight:"90vh",overflowY:"auto",boxShadow:"0 -8px 32px rgba(0,0,0,0.18)"}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:"0.875rem"}}>
              <h2 style={{margin:0,fontSize:"1rem",fontWeight:700,color:T.navy}}>匯入自訂題目</h2>
              <button onClick={()=>setShowImport(false)} style={{background:"none",border:"none",fontSize:"1.3rem",cursor:"pointer",color:T.muted,padding:"0 0.25rem"}}>✕</button>
            </div>

            {/* 格式說明 */}
            <div style={{background:"#f0f9ff",border:"1px solid #7dd3fc",borderRadius:10,padding:"0.75rem 0.9rem",marginBottom:"0.875rem",fontSize:"0.76rem",lineHeight:1.7,color:"#0c4a6e"}}>
              <div style={{fontWeight:700,marginBottom:"0.35rem",fontSize:"0.8rem"}}>✦ 格式說明</div>
              <div>頂層為陣列 <code style={{background:"#e0f2fe",padding:"0 3px",borderRadius:3}}>[ … ]</code>，每題包含以下欄位：</div>
              <table style={{width:"100%",marginTop:"0.5rem",borderCollapse:"collapse",fontSize:"0.72rem"}}>
                <thead><tr style={{background:"#bae6fd"}}>
                  <td style={{padding:"3px 6px",fontWeight:700,borderRadius:"4px 0 0 0"}}>欄位</td>
                  <td style={{padding:"3px 6px",fontWeight:700}}>型別</td>
                  <td style={{padding:"3px 6px",fontWeight:700,borderRadius:"0 4px 0 0"}}>說明</td>
                </tr></thead>
                <tbody>{[
                  ["id","string","唯一識別碼（不可與內建題重複）"],
                  ["year","string","年度，如 \"113年\""],
                  ["examCategory","string","考試類組，如 \"司律一試\""],
                  ["examGroup","string","考試別，如 \"綜合法學(二)\""],
                  ["subject","string","科目，如 \"民法\""],
                  ["text","string","題目內容"],
                  ["options","string[]","4個選項的陣列"],
                  ["answer","number","正確答案索引 0–3"],
                  ["explanation","string","解析（可選）"],
                ].map(([f,t,d])=>(
                  <tr key={f} style={{borderBottom:"1px solid #e0f2fe"}}>
                    <td style={{padding:"3px 6px",fontFamily:"monospace",color:"#0369a1",fontWeight:600}}>{f}</td>
                    <td style={{padding:"3px 6px",color:"#64748b"}}>{t}</td>
                    <td style={{padding:"3px 6px"}}>{d}</td>
                  </tr>
                ))}</tbody>
              </table>
              <div style={{marginTop:"0.6rem",fontWeight:600}}>範例：</div>
              <pre style={{margin:"0.35rem 0 0",background:"#e0f2fe",borderRadius:6,padding:"0.55rem 0.75rem",fontSize:"0.7rem",overflowX:"auto",lineHeight:1.6,color:"#0c4a6e"}}>{`[
  {
    "id": "custom-001",
    "year": "113年",
    "examCategory": "司律一試",
    "examGroup": "綜合法學(二)",
    "subject": "民法",
    "text": "下列何者正確？",
    "options": ["A選項","B選項","C選項","D選項"],
    "answer": 1,
    "explanation": "因為…（可省略）"
  }
]`}</pre>
            </div>

            {/* 輸入區 */}
            <textarea
              value={importText}
              onChange={e=>{setImportText(e.target.value);setImportErr("");setImportOk("");}}
              placeholder="在此貼上 JSON 題目陣列…"
              style={{width:"100%",height:160,padding:"0.7rem",borderRadius:10,border:`1.5px solid ${importErr?T.red:importOk?T.green:T.bdr}`,fontFamily:"monospace",fontSize:"0.77rem",resize:"vertical",boxSizing:"border-box",background:"#fafaf9",color:T.ink,outline:"none"}}
            />

            {importErr&&<div style={{fontSize:"0.8rem",color:T.red,margin:"0.35rem 0 0",display:"flex",gap:"0.3rem",alignItems:"flex-start"}}>！ {importErr}</div>}
            {importOk&&<div style={{fontSize:"0.8rem",color:T.green,margin:"0.35rem 0 0",display:"flex",gap:"0.3rem",alignItems:"flex-start"}}>{importOk}</div>}

            <div style={{display:"flex",gap:"0.5rem",marginTop:"0.75rem"}}>
              <button onClick={()=>setShowImport(false)} style={{flex:1,padding:"0.72rem",background:"transparent",color:T.ink,border:`1.5px solid ${T.bdr}`,borderRadius:12,fontSize:"0.87rem",cursor:"pointer",fontFamily:"inherit"}}>取消</button>
              <button onClick={handleImport} disabled={!importText.trim()} style={{flex:2,padding:"0.72rem",background:importText.trim()?T.blue:"#ccc",color:"#fff",border:"none",borderRadius:12,fontSize:"0.87rem",fontWeight:700,cursor:importText.trim()?"pointer":"not-allowed",fontFamily:"inherit"}}>確認匯入</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
